```cpp
class Trie {
    struct Node {
        int child[26];
        bool end = false;
        Node() { fill(std::begin(child), std::end(child), -1); }
    };
    vector<Node> tr{Node()};
public:
    void insert(string word) {
        int u = 0;
        for (char ch : word) {
            int c = ch - 'a';
            if (tr[u].child[c] == -1) {
                tr[u].child[c] = tr.size();
                tr.push_back(Node());
            }
            u = tr[u].child[c];
        }
        tr[u].end = true;
    }
    bool search(string word) {
        int u = 0;
        for (char ch : word) {
            int c = ch - 'a';
            if (tr[u].child[c] == -1) return false;
            u = tr[u].child[c];
        }
        return tr[u].end;
    }
    bool startsWith(string prefix) {
        int u = 0;
        for (char ch : prefix) {
            int c = ch - 'a';
            if (tr[u].child[c] == -1) return false;
            u = tr[u].child[c];
        }
        return true;
    }
};
```

